    14→class ErrorBoundary extends React.Component {
    15→  state = { error: null };
    16→  static getDerivedStateFromError(error) {
    17→    return { error };
    18→  }
    19→  render() {
    20→    if (this.state.error) {
    21→      return <div>Error: {this.state.error.message}</div>;
    22→    }
    23→    return this.props.children;
    24→  }
    25→}
    26→
    27→const Editor=({onClose}) =>{
    28→    const {session} = useAuth();
    29→
    30→    const [title, setTitle] = useState('')
    31→    const [editor] = useLexicalComposerContext();
    32→
    33→
    34→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
    35→
    36→    const addUploadedImagePath = useCallback((imagePath) =>{
    37→      // console.log(imagePath)
    38→      setUploadedImagePaths((prev) => [...prev, imagePath]);
    39→    }, [])
    40→    
    41→    const handleCloseEditor = useCallback(async() => { 
    42→      if(uploadedImagePaths.length > 0){
    43→        // console.log(uploadedImagePaths);
    44→        const message = await deleteJournalImage(session?.access_token, uploadedImagePaths)
    45→        if(message){
    46→          console.log(message.message)
    47→        }
    48→
    49→      }
    50→        editor.update(() => {
    51→            const state = editor.getEditorState().toJSON();
    52→            console.log(state)
    53→            
    54→            const root = $getRoot();
    55→            root.clear();
    56→            onClose();
    57→        })
    58→    }, [editor, onClose, uploadedImagePaths])
    59→
    60→    const handleCloseEditorOnSave = useCallback(async() => {
    61→      editor.update(() => {
    62→            const state = editor.getEditorState().toJSON();
    63→            console.log(state)
    64→            
    65→            const root = $getRoot();
    66→            root.clear();
    67→            onClose();
    68→      })
    69→    }, [onClose, editor])
    70→
    71→    return(
    72→        <>
    73→        <div className='editor-parent-container'>
    74→
    75→            <motion.div 
    76→            initial={{scale: 0, opacity: 0.8}}
    77→            animate={{scale: 1, opacity: 1}}
    78→            exit={{scale: 0.8, opacity: 0,}}
    79→            transition={{type: 'spring', stiffness: 260, damping: 25}}
    80→            className='editor-container'
    81→            >
    82→                <div className='editor-close-bttn-container'>
    83→                    <svg onClick={() => handleCloseEditor()} className='editor-close-bttn' xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="#FFFFFF"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
    84→                </div>
    85→
    86→                <input value={title} onChange={(e) => setTitle(e.target.value)} className='content-title-input' type="text" placeholder='Title' />
    87→
    88→                <ErrorBoundary>
    89→                    {/*this area will be the text area of an text editor */}
    90→                    <EditorInner addUploadImagesPath={addUploadedImagePath} onclose={handleCloseEditor} onCloseOnSave={handleCloseEditorOnSave} title={title}/>
    91→                </ErrorBoundary>
    92→            </motion.div>
    93→        </div>
    94→        </>
    95→    )
    96→}
    97→export default Editor;

